16	/**
17	 * Extract function names from TypeScript/JavaScript code
18	 */
19	export function extractFunctionNames(code: string): string[] {
20	  const functionNames: string[] = [];
21	  
22	  // Match function declarations: function name(...) { }
23	  const funcDeclRegex = /function\s+([a-zA-Z_$][a-zA-Z0-9_$]*)\s*\(/g;
24	  let match;
25	  while ((match = funcDeclRegex.exec(code)) !== null) {
26	    functionNames.push(match[1]);
27	  }
28	  
29	  // Match arrow functions and function expressions: const name = (...) => { } or const name = function(...) { }
30	  const arrowFuncRegex = /(?:const|let|var)\s+([a-zA-Z_$][a-zA-Z0-9_$]*)\s*=\s*(?:async\s+)?(?:\([^)]*\)|[a-zA-Z_$][a-zA-Z0-9_$]*)\s*=>/g;
31	  while ((match = arrowFuncRegex.exec(code)) !== null) {
32	    functionNames.push(match[1]);
33	  }
34	  
35	  // Match exported function declarations: export function name(...) or export const name = ...
36	  const exportFuncRegex = /export\s+(?:async\s+)?function\s+([a-zA-Z_$][a-zA-Z0-9_$]*)/g;
37	  while ((match = exportFuncRegex.exec(code)) !== null) {
38	    if (!functionNames.includes(match[1])) {
39	      functionNames.push(match[1]);
40	    }
41	  }
42	  
43	  const exportConstRegex = /export\s+(?:const|let|var)\s+([a-zA-Z_$][a-zA-Z0-9_$]*)\s*=/g;
44	  while ((match = exportConstRegex.exec(code)) !== null) {
45	    if (!functionNames.includes(match[1])) {
46	      functionNames.push(match[1]);
47	    }
48	  }
49	  
50	  return functionNames;
51	}
