53	/**
54	 * Execute utilities node - returns exported functions/objects
55	 */
56	export async function executeUtilitiesNode(
57	  node: typeof nodes.$inferSelect,
58	  organizationId: string,
59	  typeDefinitions?: string
60	): Promise<Record<string, any>> {
61	  const code = (node.config as { code?: string })?.code;
62	
63	  if (!code || code.trim() === "") {
64	    return {}; // No functions if no code
65	  }
66	
67	  try {
68	    // Extract import statements
69	    const importRegex = /^import\s+.+\s+from\s+['"].+['"];?\s*$/gm;
70	    const imports = code.match(importRegex) || [];
71	    const codeWithoutImports = code.replace(importRegex, '').trim();
72	
73	    // Convert imports to require statements
74	    const requireStatements = imports.map(importStmt => {
75	      const defaultMatch = importStmt.match(/import\s+(\w+)\s+from\s+['"](.+)['"]/);
76	      if (defaultMatch && !importStmt.includes('{')) {
77	        return `const ${defaultMatch[1]} = require('${defaultMatch[2]}');`;
78	      }
79	      
80	      const namedMatch = importStmt.match(/import\s+\{([^}]+)\}\s+from\s+['"](.+)['"]/);
81	      if (namedMatch) {
82	        const names = namedMatch[1].trim();
83	        const module = namedMatch[2];
84	        return `const { ${names} } = require('${module}');`;
85	      }
86	      
87	      const namespaceMatch = importStmt.match(/import\s+\*\s+as\s+(\w+)\s+from\s+['"](.+)['"]/);
88	      if (namespaceMatch) {
89	        return `const ${namespaceMatch[1]} = require('${namespaceMatch[2]}');`;
90	      }
91	      
92	      return importStmt;
93	    }).join('\n');
94	
95	    // Transpile TypeScript to JavaScript
96	    const transpileResult = ts.transpileModule(codeWithoutImports, {
97	      compilerOptions: {
98	        target: ts.ScriptTarget.ES2020,
99	        module: ts.ModuleKind.CommonJS,
100	      },
101	    });
102	    const jsCode = transpileResult.outputText.trim();
103	
104	    // Create module and exports objects (CommonJS pattern)
105	    const exportsObj: any = {};
106	    const moduleObj = { exports: exportsObj };
107	
108	    const orgPackagesPath = packageManager.getNodeModulesPath(organizationId);
109	
110	    // Execute in sandboxed VM context
111	    const context = createSandboxContext({
112	      organizationId,
113	      orgPackagesPath,
114	      extraGlobals: {
115	        module: moduleObj,
116	        exports: exportsObj,
117	      },
118	    });
119	
120	    const wrappedCode = `
121	      (async function() {
122	        ${requireStatements}
123	        ${jsCode}
124	        return module.exports;
125	      })()
126	    `;
127	
128	    const result = await executeInSandbox(wrappedCode, context, 5000);
129	
130	    // Return the result (module.exports after execution)
131	    return result && typeof result === 'object' ? result : {};
132	  } catch (error: any) {
133	    throw new Error(`Utilities execution failed: ${error.message}`);
134	  }
135	}
