137	/**
138	 * Execute code node - runs user TypeScript/JavaScript code
139	 */
140	export async function executeCodeNode(
141	  node: typeof nodes.$inferSelect,
142	  inputItems: ExecutionItem[],
143	  predecessorOutputs: Map<string, { nodeLabel: string; output: ExecutionItem[] }>,
144	  organizationId: string,
145	  typeDefinitions?: string,
146	  utilities?: Map<string, { label: string; exports: Record<string, any>; code: string }>
147	): Promise<ExecutionItem[]> {
148	  const code = (node.config as { code?: string })?.code;
149	
150	  if (!code || code.trim() === "") {
151	    return inputItems; // Pass through if no code
152	  }
153	
154	  try {
155	    // Extract import statements from user code
156	    const importRegex = /^import\s+.+\s+from\s+['"].+['"];?\s*$/gm;
157	    const imports = code.match(importRegex) || [];
158	    const codeWithoutImports = code.replace(importRegex, '').trim();
159	
160	    // Convert imports to require statements for runtime
161	    const requireStatements = imports.map(importStmt => {
162	      // Handle: import defaultExport from "module"
163	      const defaultMatch = importStmt.match(/import\s+(\w+)\s+from\s+['"](.+)['"]/);
164	      if (defaultMatch && !importStmt.includes('{')) {
165	        return `const ${defaultMatch[1]} = require('${defaultMatch[2]}');`;
166	      }
167	      
168	      // Handle: import { named } from "module"
169	      const namedMatch = importStmt.match(/import\s+\{([^}]+)\}\s+from\s+['"](.+)['"]/);
170	      if (namedMatch) {
171	        const names = namedMatch[1].trim();
172	        const module = namedMatch[2];
173	        return `const { ${names} } = require('${module}');`;
174	      }
175	      
176	      // Handle: import * as name from "module"
177	      const namespaceMatch = importStmt.match(/import\s+\*\s+as\s+(\w+)\s+from\s+['"](.+)['"]/);
178	      if (namespaceMatch) {
179	        return `const ${namespaceMatch[1]} = require('${namespaceMatch[2]}');`;
180	      }
181	      
182	      return importStmt;
183	    }).join('\n');
184	
185	    // Prepend type definitions to code if provided
186	    const fullCode = typeDefinitions 
187	      ? `${typeDefinitions}\n\n${code}`
188	      : code;
189	
190	    // Add global declarations for runtime functions
191	    let predecessorDeclarations = '';
192	    predecessorOutputs.forEach((data, nodeId) => {
193	      const sanitizedLabel = data.nodeLabel.replace(/[^a-zA-Z0-9_]/g, '_').replace(/^[0-9]/, '_$&');
194	      const varName = `$${sanitizedLabel}`;
195	      predecessorDeclarations += `declare const ${varName}: { json: any; input: any[] };\n`;
196	    });
197	
198	    // Generate utilities declarations
199	    let utilitiesDeclarations = '';
200	    if (utilities) {
201	      utilities.forEach((utilityData, utilityNodeId) => {
202	        const sanitizedLabel = utilityData.label.replace(/[^a-zA-Z0-9_]/g, '_').replace(/^[0-9]/, '_$&');
203	        const varName = `$${sanitizedLabel}`;
204	        
205	        // Try to get function names from exports first
206	        let functionNames = Object.keys(utilityData.exports);
207	        
208	        // If exports is empty (during type-checking), extract from code
209	        if (functionNames.length === 0 && utilityData.code) {
210	          functionNames = extractFunctionNames(utilityData.code);
211	        }
212	        
213	        // Generate type declarations for each function
214	        const exportDeclarations = functionNames
215	          .map(fnName => `  ${fnName}: (...args: any[]) => any;`)
216	          .join('\n');
217	        
218	        utilitiesDeclarations += `declare const ${varName}: {\n${exportDeclarations}\n};\n`;
219	      });
220	    }
221	
222	    const globalDeclarations = `
223	declare function require(moduleName: string): any;
224	declare const console: {
225	  log(...args: any[]): void;
226	  error(...args: any[]): void;
227	  warn(...args: any[]): void;
228	};
229	declare const $input: any[];
230	declare const $json: any;
231	declare const $inputItem: any;
232	declare const $inputAll: any[];
233	declare const $credentials: Record<string, any>;
234	${predecessorDeclarations}
235	${utilitiesDeclarations}
236	`;
237	
238	    // Wrap code in async function for type checking
239	    const wrappedCodeForTypeCheck = `
240	      ${globalDeclarations}
241	      ${typeDefinitions || ''}
242	      ${imports.join('\n')}
243	      
244	      async function __userCode__() {
245	        ${codeWithoutImports}
246	      }
247	    `;
248	
249	    // Create a virtual source file for type checking
250	    const fileName = "code.ts";
251	    const sourceFile = ts.createSourceFile(
252	      fileName,
253	      wrappedCodeForTypeCheck,
254	      ts.ScriptTarget.ES2020,
255	      true
256	    );
257	
258	    // Create compiler options
259	    const compilerOptions: ts.CompilerOptions = {
260	      target: ts.ScriptTarget.ES2020,
261	      module: ts.ModuleKind.CommonJS,
262	      lib: ['lib.es2020.d.ts'],
263	      strict: false,
264	      noImplicitAny: false,
265	      strictNullChecks: false,
266	      strictFunctionTypes: false,
267	      noUnusedLocals: false,
268	      noUnusedParameters: false,
269	      skipLibCheck: true,
270	      types: [],
271	      noResolve: true,
272	    };
273	
274	    // Create a virtual compiler host
275	    const host = ts.createCompilerHost(compilerOptions);
276	    const originalGetSourceFile = host.getSourceFile;
277	    
278	    host.getSourceFile = (name, languageVersion, onError, shouldCreateNewSourceFile) => {
279	      if (name === fileName) {
280	        return sourceFile;
281	      }
282	      return originalGetSourceFile.call(host, name, languageVersion, onError, shouldCreateNewSourceFile);
283	    };
284	
285	    // Create program for type checking
286	    const program = ts.createProgram([fileName], compilerOptions, host);
287	    
288	    // Get diagnostics (type errors)
289	    const diagnostics = ts.getPreEmitDiagnostics(program);
290	
291	    // Check for TypeScript errors
292	    if (diagnostics.length > 0) {
293	      const skipErrorPatterns = [
294	        "Cannot find module",
295	        "Cannot find name 'require'",
296	        "has no exported member",
297	        "is not a module",
298	        "Cannot redeclare",
299	        "Duplicate identifier",
300	        // ESM module system errors handled at runtime
301	        "An import declaration can only be used",
302	        "import declaration can only be used at the top level",
303	        "'import' and 'export' may appear only",
304	        "A default export must be at the top level",
305	        "default export must be at the top level",
306	        "cannot have multiple default exports",
307	        "Multiple exports of name",
308	        "export declaration can only be used",
309	        // Await/return wrapped in function
310	        "Top-level 'await'",
311	        "'await' expressions are only allowed",
312	        "'return' statement can only be used",
313	        "A 'return' statement can only be used",
314	      ];
315	      
316	      const errors = diagnostics
317	        .filter(d => d.category === ts.DiagnosticCategory.Error)
318	        .filter(diagnostic => {
319	          const message = ts.flattenDiagnosticMessageText(diagnostic.messageText, '\n');
320	          return !skipErrorPatterns.some(pattern => message.includes(pattern));
321	        })
322	        .map(diagnostic => {
323	          const message = ts.flattenDiagnosticMessageText(diagnostic.messageText, '\n');
324	          if (diagnostic.file && diagnostic.start !== undefined) {
325	            const { line, character } = diagnostic.file.getLineAndCharacterOfPosition(diagnostic.start);
326	            const typeDefLines = typeDefinitions ? typeDefinitions.split('\n').length : 0;
327	            const importLines = imports.length;
328	            const wrapperLines = 3;
329	            const adjustedLine = Math.max(1, line + 1 - typeDefLines - importLines - wrapperLines);
330	            return `Line ${adjustedLine}, Col ${character + 1}: ${message}`;
331	          }
332	          return message;
333	        });
334	
335	      if (errors.length > 0) {
336	        throw new Error(`TypeScript Validation Error:\n\n${errors.join('\n\n')}`);
337	      }
338	    }
339	
340	    // Transpile to JavaScript
341	    const transpileResult = ts.transpileModule(codeWithoutImports, {
342	      compilerOptions: {
343	        target: ts.ScriptTarget.ES2020,
344	        module: ts.ModuleKind.CommonJS,
345	      },
346	    });
347	    const jsCodeWithoutRequires = transpileResult.outputText.trim();
348	
349	    // Load credentials for this organization
350	    const credentials = await credentialService.getCredentials(organizationId);
351	
352	    const orgPackagesPath = packageManager.getNodeModulesPath(organizationId);
353	
354	    // Build extra globals for the sandbox
355	    const extraGlobals: Record<string, unknown> = {
356	      $input: inputItems,
357	      $credentials: credentials,
358	    };
359	
360	    // Add convenience variables
361	    extraGlobals.$json = inputItems && inputItems.length > 0 ? inputItems[0].json : {};
362	    extraGlobals.$inputItem = extraGlobals.$json;
363	    extraGlobals.$inputAll = inputItems || [];
364	
365	    // Add variables for all predecessor nodes
366	    predecessorOutputs.forEach((data, nodeId) => {
367	      const sanitizedLabel = data.nodeLabel.replace(/[^a-zA-Z0-9_]/g, '_').replace(/^[0-9]/, '_$&');
368	      const varName = `$${sanitizedLabel}`;
369	      extraGlobals[varName] = {
370	        json: data.output && data.output.length > 0 ? data.output[0].json : {},
371	        input: data.output || [],
372	      };
373	    });
374	
375	    // Add utilities as globals
376	    if (utilities) {
377	      utilities.forEach((utilityData, utilityNodeId) => {
378	        const sanitizedLabel = utilityData.label.replace(/[^a-zA-Z0-9_]/g, '_').replace(/^[0-9]/, '_$&');
379	        const varName = `$${sanitizedLabel}`;
380	        extraGlobals[varName] = utilityData.exports;
381	      });
382	    }
383	
384	    // Execute in sandboxed VM context
385	    const context = createSandboxContext({
386	      organizationId,
387	      orgPackagesPath,
388	      extraGlobals,
389	    });
390	
391	    const wrappedCode = `
392	      (async function() {
393	        ${requireStatements}
394	        ${jsCodeWithoutRequires}
395	      })()
396	    `;
397	
398	    const rawResult = await executeInSandbox(wrappedCode, context, 5000);
399	
400	    // Normalize result to ExecutionItem[]
401	    let outputItems: ExecutionItem[] = [];
402	
403	    if (rawResult === undefined || rawResult === null) {
404	      outputItems = [{ json: { value: null } }];
405	    } else if (Array.isArray(rawResult)) {
406	      if (rawResult.length > 0 && rawResult[0]?.json !== undefined) {
407	        outputItems = rawResult as ExecutionItem[];
408	      } else {
409	        outputItems = rawResult.map((item: unknown) => ({
410	          json:
411	            typeof item === "object" && item !== null
412	              ? (item as Record<string, unknown>)
413	              : { value: item },
414	        }));
415	      }
416	    } else if (typeof rawResult === "object") {
417	      outputItems = [{ json: rawResult as Record<string, unknown> }];
418	    } else {
419	      outputItems = [{ json: { value: rawResult } }];
420	    }
421	
422	    return outputItems;
423	  } catch (error) {
424	    throw new Error(
425	      `Code execution failed: ${
426	        error instanceof Error ? error.message : String(error)
427	      }`
428	    );
429	  }
430	}
